var surah054 = {
  number: 54,
  nameArabic: "al-Qamar",
  nameEnglish: "Al-Qamar",
  meaning: "The Moon",
  totalAyahs: 55,
  ayahs: [
    { number: 1, arabic: "ٱقْتَرَبَتِ ٱلسَّاعَةُ وَٱنشَقَّ ٱلْقَمَرُ", transliteration: "Iqtarabati alssaAAatu wainshaqqa alqamaru", transliterationB: "Iqtarabatis Saa'atu wsan shaqqal qamar", english: "The Hour (of Judgment) is nigh, and the moon is cleft asunder", romanUrdu: "Qayamat ki ghadi kareeb aa gayi aur chaand phatt (split) gaya" },
    { number: 2, arabic: "وَإِن يَرَوْا۟ ءَايَةًۭ يُعْرِضُوا۟ وَيَقُولُوا۟ سِحْرٌۭ مُّسْتَمِرٌّۭ", transliteration: "Wain yaraw ayatan yuAAridoo wayaqooloo sihrun mustamirrun", transliterationB: "Wa iny yaraw aayatany yu'ridoo wa yaqooloo sihrum mustamirr", english: "But if they see a Sign, they turn away, and say, \"This is (but) transient magic", romanUrdu: "Magar in logon ka haal yeh hai ke khwa koi nishani dekh lein mooh moadh jaatey hain aur kehte hain yeh to chalta hua jaadu hai" },
    { number: 3, arabic: "وَكَذَّبُوا۟ وَٱتَّبَعُوٓا۟ أَهْوَآءَهُمْ ۚ وَكُلُّ أَمْرٍۢ مُّسْتَقِرٌّۭ", transliteration: "Wakaththaboo waittabaAAoo ahwaahum wakullu amrin mustaqirrun", transliterationB: "Wa kazzaboo wattaba'ooo ahwaaa'ahum; wa kullu amrim mustaqirr", english: "They reject (the warning) and follow their (own) lusts but every matter has its appointed time", romanUrdu: "Inhon ne (isko bhi) jhutla diya aur apni khwahishat-e-nafs hi ki pairwi ki.Har maamlay ko Aakhir-e-kaar ek anjaam par pahunch kar rehna hai" },
    { number: 4, arabic: "وَلَقَدْ جَآءَهُم مِّنَ ٱلْأَنۢبَآءِ مَا فِيهِ مُزْدَجَرٌ", transliteration: "Walaqad jaahum mina alanbai ma feehi muzdajarun", transliterationB: "Wa laqad jaaa'ahum minal ambaaa'i maa feehi muzdajar", english: "There have already come to them Recitals wherein there is (enough) to check (them)", romanUrdu: "In logon ke saamne (pichle qaumon ke) woh halaat aa chuke hain jinmein sarkashi se baaz rakhne ke liye kafi samaan-e-ibrat hai" },
    { number: 5, arabic: "حِكْمَةٌۢ بَٰلِغَةٌۭ ۖ فَمَا تُغْنِ ٱلنُّذُرُ", transliteration: "Hikmatun balighatun fama tughnee alnnuthuru", transliterationB: "Hikmatum baalighatun famaa tughnin nuzur", english: "Mature wisdom;- but (the preaching of) Warners profits them not", romanUrdu: "Aur aisi hikmat jo nasihat ke maqsad ko ba-darja-e-atam (consummate wisdom) pura karti hain magar tambihat(warnings) in par kaargar nahin hoti" },
    { number: 6, arabic: "فَتَوَلَّ عَنْهُمْ ۘ يَوْمَ يَدْعُ ٱلدَّاعِ إِلَىٰ شَىْءٍۢ نُّكُرٍ", transliteration: "Fatawalla AAanhum yawma yadAAu alddaAAi ila shayin nukurin", transliterationB: "Fatawalla 'anhum; yawma yad'ud daa'i ilaa shai 'in nukur", english: "Therefore, (O Prophet,) turn away from them. The Day that the Caller will call (them) to a terrible affair", romanUrdu: "Pas aey Nabi, insey rukh pher lo. Jis roz pukarne wala ek sakht nagawaar cheez ki taraf pukarega" },
    { number: 7, arabic: "خُشَّعًا أَبْصَٰرُهُمْ يَخْرُجُونَ مِنَ ٱلْأَجْدَاثِ كَأَنَّهُمْ جَرَادٌۭ مُّنتَشِرٌۭ", transliteration: "KhushshaAAan absaruhum yakhrujoona mina alajdathi kaannahum jaradun muntashirun", transliterationB: "khushsha'an absaaruhum yakrujoona minal ajdaasi ka annahum jaraadum muntashir", english: "They will come forth,- their eyes humbled - from (their) graves, (torpid) like locusts scattered abroad", romanUrdu: "Log sehmi hui (down-cast) nigaahon ke saath apni qabraon se is tarah niklenge goya woh bikhri huyi tiddiyan (locusts) hain" },
    { number: 8, arabic: "مُّهْطِعِينَ إِلَى ٱلدَّاعِ ۖ يَقُولُ ٱلْكَٰفِرُونَ هَٰذَا يَوْمٌ عَسِرٌۭ", transliteration: "MuhtiAAeena ila alddaAAi yaqoolu alkafiroona hatha yawmun AAasirun", transliterationB: "Muhti'eena ilad daa'i yaqoolul kafiroona haazaa yawmun 'asir", english: "Hastening, with eyes transfixed, towards the Caller!- \"Hard is this Day!\", the Unbelievers will say", romanUrdu: "Pukarne wale ki taraf daudey jaa rahey hongey Aur wahi munkireen (jo duniya mein iska inkar karte thay)us waqt kahenge ke yeh din to bada kathin hai" },
    { number: 9, arabic: "۞ كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ فَكَذَّبُوا۟ عَبْدَنَا وَقَالُوا۟ مَجْنُونٌۭ وَٱزْدُجِرَ", transliteration: "Kaththabat qablahum qawmu noohin fakaththaboo AAabdana waqaloo majnoonun waizdujira", transliterationB: "Kazzabat qablahum qawmu Noohin fakazzaboo 'abdanaa wa qaaloo majnoo nunw wazdujir", english: "Before them the People of Noah rejected (their messenger): they rejected Our servant, and said, \"Here is one possessed!\", and he was driven out", romanUrdu: "Insey pehle Nooh ki qaum jhutla chuki hai. Unhon ne hamare bandey ko jhoota karar diya aur kaha ke yeh deewana hai, aur woh buri tarah jhidka (rebuffed) gaya" },
    { number: 10, arabic: "فَدَعَا رَبَّهُۥٓ أَنِّى مَغْلُوبٌۭ فَٱنتَصِرْ", transliteration: "FadaAAa rabbahu annee maghloobun faintasir", transliterationB: "Fada'aa Rabbahooo annee maghloobun fantasir", english: "Then he called on his Lord: \"I am one overcome: do Thou then help (me)", romanUrdu: "Aakhir-e-kaar usne apne Rubb ko pukara ke “main magloob ho chuka , ab tu inse inteqam le”" },
    { number: 11, arabic: "فَفَتَحْنَآ أَبْوَٰبَ ٱلسَّمَآءِ بِمَآءٍۢ مُّنْهَمِرٍۢ", transliteration: "Fafatahna abwaba alssamai bimain munhamirin", transliterationB: "Fafatahnaaa abwaabas sa maaa'i bimaa'im munhamir", english: "So We opened the gates of heaven, with water pouring forth", romanUrdu: "Tab humne mausla-dhaar baarish se aasmaan ke darwaze khol diye aur zameen ko phaad kar chasmon mein tabdeel kar diya" },
    { number: 12, arabic: "وَفَجَّرْنَا ٱلْأَرْضَ عُيُونًۭا فَٱلْتَقَى ٱلْمَآءُ عَلَىٰٓ أَمْرٍۢ قَدْ قُدِرَ", transliteration: "Wafajjarna alarda AAuyoonan failtaqa almao AAala amrin qad qudira", transliterationB: "Wa fajjamal arda 'uyoonan faltaqal maaa'u 'alaaa amrin qad qudir", english: "And We caused the earth to gush forth with springs, so the waters met (and rose) to the extent decreed", romanUrdu: "Aur yeh saara paani us kaam ko pura karne ke liye mil gaya jo mukaddar ho chuka tha" },
    { number: 13, arabic: "وَحَمَلْنَٰهُ عَلَىٰ ذَاتِ أَلْوَٰحٍۢ وَدُسُرٍۢ", transliteration: "Wahamalnahu AAala thati alwahin wadusurin", transliterationB: "Wa hamalnaahu 'alaa zaati alwaahinw wa dusur", english: "But We bore him on an (Ark) made of broad planks and caulked with palm-fibre", romanUrdu: "Aur Nooh ko humne ek takhaton(planks) aur keelon (nails) wali par sawar kar diya" },
    { number: 14, arabic: "تَجْرِى بِأَعْيُنِنَا جَزَآءًۭ لِّمَن كَانَ كُفِرَ", transliteration: "Tajree biaAAyunina jazaan liman kana kufira", transliterationB: "Tajree bi a'yuninaa jazaaa 'al liman kaana kufir", english: "She floats under our eyes (and care): a recompense to one who had been rejected (with scorn)", romanUrdu: "Jo hamari nigrani mein chal rahi thi .yeh tha badla us shaks ki khatir jiski na-qadri ki gayi thi" },
    { number: 15, arabic: "وَلَقَد تَّرَكْنَٰهَآ ءَايَةًۭ فَهَلْ مِن مُّدَّكِرٍۢ", transliteration: "Walaqad taraknaha ayatan fahal min muddakirin", transliterationB: "Wa laqat taraknaahaad aayatan fahal mim muddakir", english: "And We have left this as a Sign (for all time): then is there any that will receive admonition", romanUrdu: "Us kashti ko humne ek nishani bana kar chodh diya, phir koi hai nasihat qabool karne wala" },
    { number: 16, arabic: "فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ", transliteration: "Fakayfa kana AAathabee wanuthuri", transliterationB: "Fakaifa kaana 'azaabee wa nuzur", english: "But how (terrible) was My Penalty and My Warning", romanUrdu: "Dekhlo, kaisa tha mera azaab aur kaisi thi meri tambihaat (warnings)" },
    { number: 17, arabic: "وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍۢ", transliteration: "Walaqad yassarna alqurana lilththikri fahal min muddakirin", transliterationB: "Wa laqad yassamal Quraana liz zikri fahal mimmuddakir", english: "And We have indeed made the Qur'an easy to understand and remember: then is there any that will receive admonition", romanUrdu: "Humne is Quran ko nasihat ke liye aasaan zariya bana diya hai, phir kya hai koi nasihat qabool karne wala" },
    { number: 18, arabic: "كَذَّبَتْ عَادٌۭ فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ", transliteration: "Kaththabat AAadun fakayfa kana AAathabee wanuthuri", transliterationB: "Kazzabat 'Aadun fakaifa kaana 'azaabee wa nuzur", english: "The 'Ad (people) (too) rejected (Truth): then how terrible was My Penalty and My Warning", romanUrdu: "Aad ne jhutlaya, to dekhlo ke kaisa tha mera azaab aur kaisi thi meri tambihaat (warnings)" },
    { number: 19, arabic: "إِنَّآ أَرْسَلْنَا عَلَيْهِمْ رِيحًۭا صَرْصَرًۭا فِى يَوْمِ نَحْسٍۢ مُّسْتَمِرٍّۢ", transliteration: "Inna arsalna AAalayhim reehan sarsaran fee yawmi nahsin mustamirrin", transliterationB: "Innaa arsalnaa 'alaihim reehan sarsaran fee Yawmi nahsim mustamirr", english: "For We sent against them a furious wind, on a Day of violent Disaster", romanUrdu: "Humne ek paiham nahusat (unremitting misfortune) ke din sakht toofani hawa unpar bhej di jo logon ko utha utha kar is tarah phenk rahi thi" },
    { number: 20, arabic: "تَنزِعُ ٱلنَّاسَ كَأَنَّهُمْ أَعْجَازُ نَخْلٍۢ مُّنقَعِرٍۢ", transliteration: "TanziAAu alnnasa kaannahum aAAjazu nakhlin munqaAAirin", transliterationB: "Tanzi;un naasa ka anna huma'jaazu nakhlim munqa'ir", english: "Plucking out men as if they were roots of palm-trees torn up (from the ground)", romanUrdu: "Jaise woh jadd (roots) se ukhade huey khajoor ke taney (trunks) hon" },
    { number: 21, arabic: "فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ", transliteration: "Fakayfa kana AAathabee wanuthuri", transliterationB: "Fakaifa kaana 'azaabee wa nuzur", english: "Yea, how (terrible) was My Penalty and My Warning", romanUrdu: "Pas dekhlo ke kaisa tha mera azaab aur kaisi thi meri tambihaat (warnings)" },
    { number: 22, arabic: "وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍۢ", transliteration: "Walaqad yassarna alqurana lilththikri fahal min muddakirin", transliterationB: "Wa laqad yassamal Quraana liz zikri fahal mim muddakir", english: "But We have indeed made the Qur'an easy to understand and remember: then is there any that will receive admonition", romanUrdu: "Humne is Quran ko nasihat ke liye aasaan zariya bana diya hai, phir kya hai koi nasihat qabool karne wala" },
    { number: 23, arabic: "كَذَّبَتْ ثَمُودُ بِٱلنُّذُرِ", transliteration: "Kaththabat thamoodu bialnnuthuri", transliterationB: "Kazzabat Samoodu binnuzur", english: "The Thamud (also) rejected (their) Warners", romanUrdu: "Samood ne tambihaat ko jhutlaya" },
    { number: 24, arabic: "فَقَالُوٓا۟ أَبَشَرًۭا مِّنَّا وَٰحِدًۭا نَّتَّبِعُهُۥٓ إِنَّآ إِذًۭا لَّفِى ضَلَٰلٍۢ وَسُعُرٍ", transliteration: "Faqaloo abasharan minna wahidan nattabiAAuhu inna ithan lafee dalalin wasuAAurin", transliterationB: "Faqaalooo a-basharam minnaa waahidan nattabi'uhooo innaa izal lafee dalaalinw wa su'ur", english: "For they said: \"What! a man! a Solitary one from among ourselves! shall we follow such a one? Truly should we then be straying in mind, and mad", romanUrdu: "Aur kehne lagey “Ek akela aadmi jo hum hi mein se hai kya ab hum uske peechey chalein? Iska ittibaah hum qabool karlein to iske maani yeh hongey ke hum behak gaye hain aur hamari aqal maari gayi hai" },
    { number: 25, arabic: "أَءُلْقِىَ ٱلذِّكْرُ عَلَيْهِ مِنۢ بَيْنِنَا بَلْ هُوَ كَذَّابٌ أَشِرٌۭ", transliteration: "Aolqiya alththikru AAalayhi min baynina bal huwa kaththabun ashirun", transliterationB: "A-ulqiyaz zikru 'alaihi mim baininaa bal huwa kazzaabun ashir", english: "Is it that the Message is sent to him, of all people amongst us? Nay, he is a liar, an insolent one", romanUrdu: "Kya hamare darmiyan bas yahi ek shaks tha jispar khuda ka zikr nazil kiya gaya? nahin, balke yeh parle darje ka jhoota aur bar-khud galat (insolent liar)hai”" },
    { number: 26, arabic: "سَيَعْلَمُونَ غَدًۭا مَّنِ ٱلْكَذَّابُ ٱلْأَشِرُ", transliteration: "SayaAAlamoona ghadan mani alkaththabu alashiru", transliterationB: "Sa-ya'lamoona ghadam manil kazzaabul ashir", english: "Ah! they will know on the morrow, which is the liar, the insolent one", romanUrdu: "(Humne apne paigambar se kaha) “ Kal hi inhein maaloom hua jata hai ke kaun parle darje ka jhoota aur bar khud galat hai" },
    { number: 27, arabic: "إِنَّا مُرْسِلُوا۟ ٱلنَّاقَةِ فِتْنَةًۭ لَّهُمْ فَٱرْتَقِبْهُمْ وَٱصْطَبِرْ", transliteration: "Inna mursiloo alnnaqati fitnatan lahum fairtaqibhum waistabir", transliterationB: "Innaa mursilun naaqati fitnatal lahum fartaqibhum wastabir", english: "For We will send the she-camel by way of trial for them. So watch them, (O Salih), and possess thyself in patience", romanUrdu: "Hum ountni (she-camel) ko inke liye fitna bana kar bhej rahe hain, ab zara sabr ke saath dekh ke inka kya anjaam hota hai" },
    { number: 28, arabic: "وَنَبِّئْهُمْ أَنَّ ٱلْمَآءَ قِسْمَةٌۢ بَيْنَهُمْ ۖ كُلُّ شِرْبٍۢ مُّحْتَضَرٌۭ", transliteration: "Wanabbihum anna almaa qismatun baynahum kullu shirbin muhtadarun", transliterationB: "Wa nabbi'hum annal maaa'a qismatum bainahum kullu shirbim muhtadar", english: "And tell them that the water is to be divided between them: Each one's right to drink being brought forward (by suitable turns)", romanUrdu: "Inko jata de ke paani inke aur ountni(she-camel) ke darmiyaan takseem hoga aur har ek apni baari ke din paani par aayega”" },
    { number: 29, arabic: "فَنَادَوْا۟ صَاحِبَهُمْ فَتَعَاطَىٰ فَعَقَرَ", transliteration: "Fanadaw sahibahum fataAAata faAAaqara", transliterationB: "Fanaadaw saahibahum fata'aataa fa'aqar", english: "But they called to their companion, and he took a sword in hand, and hamstrung (her)", romanUrdu: "Aakhir-e-kaar un logon ne apne aadmi ko pukara aur usne is kaam ka beda uthaya aur ountni (she-camel) ko maar dala" },
    { number: 30, arabic: "فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ", transliteration: "Fakayfa kana AAathabee wanuthuri", transliterationB: "Fakaifa kaana 'azaabee wa nuzur", english: "Ah! how (terrible) was My Penalty and My Warning", romanUrdu: "Phir dekh lo ke kaisa tha mera azaab aur kaisi thi meri tambeehat (warnings)" },
    { number: 31, arabic: "إِنَّآ أَرْسَلْنَا عَلَيْهِمْ صَيْحَةًۭ وَٰحِدَةًۭ فَكَانُوا۟ كَهَشِيمِ ٱلْمُحْتَظِرِ", transliteration: "Inna arsalna AAalayhim sayhatan wahidatan fakanoo kahasheemi almuhtathiri", transliterationB: "Innaaa arsalnaa 'alaihim saihatanw waahidatan fakaano kahasheemil muhtazir", english: "For We sent against them a single Mighty Blast, and they became like the dry stubble used by one who pens cattle", romanUrdu: "Humne unpar bas ek hi dhamaka chodha aur woh baade wale ki rondhi hui baad ke taraah bhus ho kar reh gaya. (Lo! We sent upon them one Shout, and they became as the dry twigs (rejected by) the builder of a cattle-fold" },
    { number: 32, arabic: "وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍۢ", transliteration: "Walaqad yassarna alqurana lilththikri fahal min muddakirin", transliterationB: "Wa laqad yassarnal quraana liz zikri fahal mim muddakir", english: "And We have indeed made the Qur'an easy to understand and remember: then is there any that will receive admonition", romanUrdu: "Humne is Quran ko nasihat ke liye aasaan zariya bana diya hai, ab hai koi nasihat qabool karne wala" },
    { number: 33, arabic: "كَذَّبَتْ قَوْمُ لُوطٍۭ بِٱلنُّذُرِ", transliteration: "Kaththabat qawmu lootin bialnnuthuri", transliterationB: "Kazzabat qawmu lootim binnuzur", english: "The people of Lut rejected (his) warning", romanUrdu: "Lut ki qaum ne tambihat ko jhutlaya" },
    { number: 34, arabic: "إِنَّآ أَرْسَلْنَا عَلَيْهِمْ حَاصِبًا إِلَّآ ءَالَ لُوطٍۢ ۖ نَّجَّيْنَٰهُم بِسَحَرٍۢ", transliteration: "Inna arsalna AAalayhim hasiban illa ala lootin najjaynahum bisaharin", transliterationB: "Innaa arsalnaa 'alaihim haasiban illaaa aala Loot najjainaahum bisahar", english: "We sent against them a violent Tornado with showers of stones, (which destroyed them), except Lut's household: them We delivered by early Dawn", romanUrdu: "Aur humne pattharao karne wali hawa is par bhej di. Sirf Lut ke ghar wale ussey mehfooz rahe" },
    { number: 35, arabic: "نِّعْمَةًۭ مِّنْ عِندِنَا ۚ كَذَٰلِكَ نَجْزِى مَن شَكَرَ", transliteration: "NiAAmatan min AAindina kathalika najzee man shakara", transliterationB: "Ni'matam min 'indinaa; kazaalika najzee man shakar", english: "As a Grace from Us: thus do We reward those who give thanks", romanUrdu: "Unko humne apne fazl se raat ke pichle pehar bacha kar nikal diya. Yeh jaza dete hai hum har us shaks ko jo shukar guzar hota hai" },
    { number: 36, arabic: "وَلَقَدْ أَنذَرَهُم بَطْشَتَنَا فَتَمَارَوْا۟ بِٱلنُّذُرِ", transliteration: "Walaqad antharahum batshatana fatamaraw bialnnuthuri", transliterationB: "Wa laqad anzarahum batshatanaa fatamaaraw binnuzur", english: "And (Lut) did warn them of Our Punishment, but they disputed about the Warning", romanUrdu: "Lut ne apni qaum ke logon ko hamari pakad se khabardaar kiya magar woh saari tambihat ko mashkuk (doubtful) samajh kar baaton mein udate rahey" },
    { number: 37, arabic: "وَلَقَدْ رَٰوَدُوهُ عَن ضَيْفِهِۦ فَطَمَسْنَآ أَعْيُنَهُمْ فَذُوقُوا۟ عَذَابِى وَنُذُرِ", transliteration: "Walaqad rawadoohu AAan dayfihi fatamasna aAAyunahum fathooqoo AAathabee wanuthuri", transliterationB: "Wa laqad raawadoohu 'andaifee fatamasnaaa a'yunahum fazooqoo 'azaabee wa nuzur", english: "And they even sought to snatch away his guests from him, but We blinded their eyes. (They heard:) \"Now taste ye My Wrath and My Warning", romanUrdu: "Phir unhon ne usey apne mehmano ki hifazat se baaz rakhne ki koshish ki. Aakhir-e-kaar humne unki aankhein moond-di (blinded), ke chakkho ab mera azaab aur meri tambihaat ka maza" },
    { number: 38, arabic: "وَلَقَدْ صَبَّحَهُم بُكْرَةً عَذَابٌۭ مُّسْتَقِرٌّۭ", transliteration: "Walaqad sabbahahum bukratan AAathabun mustaqirrun", transliterationB: "Wa laqad sabbahahum bukratan 'azaabum mustaqirr", english: "Early on the morrow an abiding Punishment seized them", romanUrdu: "Subah sawerey hi ek atal azaab ne unko aa liya" },
    { number: 39, arabic: "فَذُوقُوا۟ عَذَابِى وَنُذُرِ", transliteration: "Fathooqoo AAathabee wanuthuri", transliterationB: "Fazooqoo 'azaabee wa nuzur", english: "So taste ye My Wrath and My Warning", romanUrdu: "Chakkho mazaa ab mere azaab ka aur meri tambihaat ka" },
    { number: 40, arabic: "وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍۢ", transliteration: "Walaqad yassarna alqurana lilththikri fahal min muddakirin", transliterationB: "Wa laqad yassarnal Quraana liz zikri fahal mim muddakir", english: "And We have indeed made the Qur'an easy to understand and remember: then is there any that will receive admonition", romanUrdu: "Humne is Quran ko nasihat ke liye aasaan zariya bana diya hai, pas hai koi nasihat qabool karne wala" },
    { number: 41, arabic: "وَلَقَدْ جَآءَ ءَالَ فِرْعَوْنَ ٱلنُّذُرُ", transliteration: "Walaqad jaa ala firAAawna alnnuthuru", transliterationB: "Wa laqad jaaa'a Aala Fir'awnan nuzur", english: "To the People of Pharaoh, too, aforetime, came Warners (from Allah)", romanUrdu: "Aur aal-e-Firoun ke paas bhi tambihaat aayi thi" },
    { number: 42, arabic: "كَذَّبُوا۟ بِـَٔايَٰتِنَا كُلِّهَا فَأَخَذْنَٰهُمْ أَخْذَ عَزِيزٍۢ مُّقْتَدِرٍ", transliteration: "Kaththaboo biayatina kulliha faakhathnahum akhtha AAazeezin muqtadirin", transliterationB: "Kazzaboo bi Aayaatinaa kullihaa fa akhaznaahum akhza 'azeezim muqtadir", english: "The (people) rejected all Our Signs; but We seized them with such Penalty (as comes) from One Exalted in Power, able to carry out His Will", romanUrdu: "Magar unhon ne hamari saari nishaniyon ko jhutla diya. Aakhir ko humne unhein pakda jis taraah koi zabardast qudrat wala pakadta hai" },
    { number: 43, arabic: "أَكُفَّارُكُمْ خَيْرٌۭ مِّنْ أُو۟لَٰٓئِكُمْ أَمْ لَكُم بَرَآءَةٌۭ فِى ٱلزُّبُرِ", transliteration: "Akuffarukum khayrun min olaikum am lakum baraatun fee alzzuburi", transliterationB: "Akuffaarukum khairum min ulaaa'ikum am lakum baraaa'atun fiz Zubur", english: "Are your Unbelievers, (O Quraish), better than they? Or have ye an immunity in the Sacred Books", romanUrdu: "Kya tumhare kuffar kuch un logon se behtar hain? Ya aasmani kitaabon mein tumhare liye koi maafi likhi hui hai" },
    { number: 44, arabic: "أَمْ يَقُولُونَ نَحْنُ جَمِيعٌۭ مُّنتَصِرٌۭ", transliteration: "Am yaqooloona nahnu jameeAAun muntasirun", transliterationB: "Am yaqooloona nahnu jamee'um muntasir", english: "Or do they say: \"We acting together can defend ourselves", romanUrdu: "Ya in logon ka kehna yeh hai ke hum ek mazboot jattha (jamaat) hain, apna bachao kar lengey" },
    { number: 45, arabic: "سَيُهْزَمُ ٱلْجَمْعُ وَيُوَلُّونَ ٱلدُّبُرَ", transliteration: "Sayuhzamu aljamAAu wayuwalloona alddubura", transliterationB: "Sa yuhzamul jam'u wa yuwalloonad dubur", english: "Soon will their multitude be put to flight, and they will show their backs", romanUrdu: "Ankareeb yeh jattha(jamaat) shikhast kha jayega aur yeh sab peeth pheir kar bhaagte nazar aayenge" },
    { number: 46, arabic: "بَلِ ٱلسَّاعَةُ مَوْعِدُهُمْ وَٱلسَّاعَةُ أَدْهَىٰ وَأَمَرُّ", transliteration: "Bali alssaAAatu mawAAiduhum waalssaAAatu adha waamarru", transliterationB: "Balis Saa'atu maw'iduhum was Saa'atu adhaa wa amarr", english: "Nay, the Hour (of Judgment) is the time promised them (for their full recompense): And that Hour will be most grievous and most bitter", romanUrdu: "Balke insey nimatne ke liye asal waade ka waqt to qayamat hai aur woh badi aafat aur zyaada talkh-saa-at (badi sakht aur kadwi cheez) hai" },
    { number: 47, arabic: "إِنَّ ٱلْمُجْرِمِينَ فِى ضَلَٰلٍۢ وَسُعُرٍۢ", transliteration: "Inna almujrimeena fee dalalin wasuAAurin", transliterationB: "Innal mujrimeena fee dalaalinw wa su'ur", english: "Truly those in sin are the ones straying in mind, and mad", romanUrdu: "Yeh mujrim log dar haqeeqat galat fehmi mein mubtala hain aur inki aqal maari gayi hai" },
    { number: 48, arabic: "يَوْمَ يُسْحَبُونَ فِى ٱلنَّارِ عَلَىٰ وُجُوهِهِمْ ذُوقُوا۟ مَسَّ سَقَرَ", transliteration: "Yawma yushaboona fee alnnari AAala wujoohihim thooqoo massa saqara", transliterationB: "Yawma yushaboona fin Naari'alaa wujoohimim zooqoo massa saqar", english: "The Day they will be dragged through the Fire on their faces, (they will hear:) \"Taste ye the touch of Hell", romanUrdu: "Jis roz yeh mooh ke bal aag mein ghaseetey jayenge us roz insey kaha jayega ke ab chakkho jahannum ki lapat ka maza" },
    { number: 49, arabic: "إِنَّا كُلَّ شَىْءٍ خَلَقْنَٰهُ بِقَدَرٍۢ", transliteration: "Inna kulla shayin khalaqnahu biqadarin", transliterationB: "Innaa kulla shai'in khalaqnaahu biqadar", english: "Verily, all things have We created in proportion and measure", romanUrdu: "Humne har cheez ek taqdeer ke saath paida ki hai" },
    { number: 50, arabic: "وَمَآ أَمْرُنَآ إِلَّا وَٰحِدَةٌۭ كَلَمْحٍۭ بِٱلْبَصَرِ", transliteration: "Wama amruna illa wahidatun kalamhin bialbasari", transliterationB: "Wa maaa amrunaaa illaa waahidatun kalamhim bilbasar", english: "And Our Command is but a single (Act),- like the twinkling of an eye", romanUrdu: "Aur hamara hukum bas ek hi hukum hota hai aur palak jhapakate (twinkling of an eye) woh amal mein aa jata hai" },
    { number: 51, arabic: "وَلَقَدْ أَهْلَكْنَآ أَشْيَاعَكُمْ فَهَلْ مِن مُّدَّكِرٍۢ", transliteration: "Walaqad ahlakna ashyaAAakum fahal min muddakirin", transliterationB: "Wa laqad ahlaknaaa ashyaa'akum fahal mim muddakir", english: "And (oft) in the past, have We destroyed gangs like unto you: then is there any that will receive admonition", romanUrdu: "Tum jaisey bahut-soon ko hum halak kar chuke hain. Phir hai koi nasihat qabool karne wala" },
    { number: 52, arabic: "وَكُلُّ شَىْءٍۢ فَعَلُوهُ فِى ٱلزُّبُرِ", transliteration: "Wakullu shayin faAAaloohu fee alzzuburi", transliterationB: "Wa kullu shai'in fa'aloohu fiz Zubur", english: "All that they do is noted in (their) Books (of Deeds)", romanUrdu: "Jo kuch inhon ne kiya hai woh sab daftaron (office) mein darj hai" },
    { number: 53, arabic: "وَكُلُّ صَغِيرٍۢ وَكَبِيرٍۢ مُّسْتَطَرٌ", transliteration: "Wakullu sagheerin wakabeerin mustatarun", transliterationB: "Wa kullu sagheerinw wa kabeerim mustatar", english: "Every matter, small and great, is on record", romanUrdu: "Aur har choti badi baat likhi hui maujood hai" },
    { number: 54, arabic: "إِنَّ ٱلْمُتَّقِينَ فِى جَنَّٰتٍۢ وَنَهَرٍۢ", transliteration: "Inna almuttaqeena fee jannatin wanaharin", transliterationB: "Innal muttaqeena fee jannaatinw wa nahar", english: "As to the Righteous, they will be in the midst of Gardens and Rivers", romanUrdu: "Nafarmani se parhez karne waley yaqeenan baaghon aur neharon mein hongey" },
    { number: 55, arabic: "فِى مَقْعَدِ صِدْقٍ عِندَ مَلِيكٍۢ مُّقْتَدِرٍۭ", transliteration: "Fee maqAAadi sidqin AAinda maleekin muqtadirin", transliterationB: "Fee maq'adi sidqin 'inda Maleekim Muqtadir", english: "In an Assembly of Truth, in the Presence of a Sovereign Omnipotent", romanUrdu: "Sacchi izzat ki jagah, badey zeeh-iqtedar baadshah ke kareeb" }
  ]
};
